content:
  letter-spacing: 2px;
  text-transform: uppercase;
  margin-bottom: 24px;
}

.slide-title {
  font-size: 58px;
  font-weight: 800;
  line-height: 1.15;
  letter-spacing: -1px;
  color: var(--text-primary);
  margin-bottom: 16px;
}
.slide-subtitle {
  font-size: 28px;
  font-weight: 500;
  line-height: 1.5;
  color: var(--text-secondary);
  margin-bottom: 32px;
}

.hl-blue { color: var(--accent-blue); }
.hl-cyan { color: var(--accent-cyan); }
.hl-green { color: var(--accent-green); }
.hl-amber { color: var(--accent-amber); }
.hl-purple { color: var(--accent-purple); }
.hl-red { color: var(--accent-red); }

.footer {
  position: absolute;
  bottom: 48px;
  left: 72px;
  right: 72px;
  display: flex;
  justify-content: space-between;
  align-items: center;
  font-size: 18px;
  color: var(--text-muted);
  font-weight: 500;
}

.tag {
  display: inline-block;
  font-size: 20px;
  font-weight: 600;
  padding: 8px 20px;
  border-radius: 100px;
  margin: 4px 6px 4px 0;
}

.card {
  background: var(--bg-card);
  border-radius: 16px;
  padding: 32px;
}

.insight-box {
  border-radius: 16px;
  padding: 24px 28px;
  font-size: 22px;
  font-weight: 500;
  line-height: 1.5;
  color: var(--text-primary);
}

.card-header {
  font-size: 18px;
  font-weight: 700;
  letter-spacing: 2px;
  text-transform: uppercase;
  margin-bottom: 12px;
}

.stat-value {
  font-size: 56px;
  font-weight: 800;
  line-height: 1.2;
}

.stat-label {
  font-size: 18px;
  font-weight: 500;
  color: var(--text-secondary);
  margin-top: 4px;
}
